import { ColorArea } from '@tale-ui/react/color-area';
import { ColorSlider } from '@tale-ui/react/color-slider';

export function ColorAreaPicker() {
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-s)' }}>
      <ColorArea.Root
        defaultValue="hsl(0, 100%, 50%)"
        xChannel="saturation"
        yChannel="lightness"
      >
        <ColorArea.Thumb />
      </ColorArea.Root>
      <ColorSlider.Root channel="hue" defaultValue="hsl(0, 100%, 50%)">
        <ColorSlider.Label>Hue</ColorSlider.Label>
        <ColorSlider.Output />
        <ColorSlider.Track>
          <ColorSlider.Thumb />
        </ColorSlider.Track>
      </ColorSlider.Root>
    </div>
  );
}
